import{_ as a,o,c as t,ak as n,an as i}from"./chunks/framework.B9OfcISu.js";const h=JSON.parse('{"title":"npm","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"setup/package-managers/npm.md","filePath":"setup/package-managers/npm.md"}'),l={name:"setup/package-managers/npm.md"};function r(s,e,c,d,p,u){return o(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="npm" tabindex="-1"><img src="'+i+'" style="display:inline-block;vertical-align:middle;height:48px;margin-right:8px;"> npm <a class="header-anchor" href="#npm" aria-label="Permalink to “npm”">​</a></h1><p>npm is the default package manager for Node.js and the world&#39;s largest software registry, hosting over two million packages of open-source JavaScript code.</p><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to “Installation”">​</a></h2><p>Get the desired version for your platform, using <code>nvm</code> with <code>npm</code> at <a href="https://nodejs.org/en/download" target="_blank" rel="noreferrer">https://nodejs.org/en/download</a> and follow the instructions.</p><h2 id="initialization" tabindex="-1">Initialization <a class="header-anchor" href="#initialization" aria-label="Permalink to “Initialization”">​</a></h2><ul><li><p><code>npm init</code>: If you&#39;re working on a fresh project, to use npm you need a package.json file. This file acts as the &quot;manifest&quot; for your project, listing your metadata and dependencies.</p></li><li><p><code>npm ci</code>: If you&#39;re working on an imported/existing project, you need to sync/install locally the required libraries listed in an existing <code>package.json</code>.</p></li></ul><h2 id="package-management" tabindex="-1">Package Management <a class="header-anchor" href="#package-management" aria-label="Permalink to “Package Management”">​</a></h2><ul><li><code>npm install &lt;package_name&gt;</code>: Downloads a package and adds it to your project.</li><li><code>npm update</code>: Updates packages to the latest version allowed by your version ranges.</li><li><code>npm uninstall &lt;package&gt;</code>: Removes a package from your project and the package.json.</li></ul><p>When you install a package, two major things happen in your project folder:</p><ul><li>The actual code for your downloaded packages lives in the <code>node_modules</code> folder.</li></ul><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Never manually edit files in this folder. Also, add node_modules to your .gitignore file; you don&#39;t want to upload thousands of third-party files to GitHub!</p></div><ul><li>The <code>package.json</code> file gets automatically generated. It records the exact version of every installed package to ensure that if someone else downloads your project, they get the exact same setup you have.</li></ul><h2 id="lifecycle" tabindex="-1">Lifecycle <a class="header-anchor" href="#lifecycle" aria-label="Permalink to “Lifecycle”">​</a></h2><p>When you type <code>npm run &lt;name&gt;</code>, npm looks into your <code>package.json</code> under the &quot;scripts&quot; key and executes the string associated with that name.</p><ul><li><code>npm run lint</code>: Analyze the code for syntax errors, style violations and best practice warnings</li></ul><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>You can fix basic formatting issues automatically by running <code>npm run lint -- --fix</code> instead.</p></div><ul><li><code>npm run dev</code>: Live preview your code</li><li><code>npm run build</code>: Turn your code into a high-performance bundle (for production)</li></ul>',17)])])}const g=a(l,[["render",r]]);export{h as __pageData,g as default};
